    toc: [ { id: "legal-status", title: "legal-status", level: 2 }, { id: "legal-status-of-crypto-in-vietnam", title: "Legal Status of Crypto in Vietnam", level: 2 }, { id: "current-tax", title: "current-tax", level: 2 }, { id: "current-tax-obligations", title: "Current Tax Obligations", level: 2 }, { id: "upcoming-regulation", title: "upcoming-regulation", level: 2 }, { id: "upcoming-regulation", title: "Upcoming Regulation", level: 2 }, { id: "practical-steps", title: "practical-steps", level: 2 }, { id: "practical-steps-for-compliance", title: "Practical Steps for Compliance", level: 2 } ],
    faqs: [ { question: "Is crypto legal in Vietnam?", answer: "Crypto exists in a legal gray area. The State Bank of Vietnam has banned using crypto as a payment method, and crypto is not recognized as legal tender. However, owning, buying, and selling crypto as an investment or asset is not explicitly prohibited. The legal framework is evolving." }, { question: "Do I need to pay tax on crypto gains in Vietnam?", answer: "While there is no specific crypto tax law, gains from crypto could be subject to personal income tax under general provisions. Income from the transfer of capital or assets may attract a 20% capital transfer tax or 2% of transaction value. The exact application to crypto is unclear and depends on regulatory interpretation." }, { question: "Is the Vietnamese government creating crypto regulations?", answer: "Yes. The Vietnamese government has tasked multiple ministries with developing a legal framework for crypto. The Ministry of Finance, State Bank of Vietnam, and Ministry of Justice are all involved in drafting regulations. A comprehensive framework addressing taxation, licensing, and oversight is expected." }, { question: "Should I keep records of my crypto trades in Vietnam?", answer: "Absolutely. Even without specific regulations, maintaining detailed transaction records is essential. When regulations are enacted, historical records will be needed to establish cost basis and calculate gains. Records should include dates, amounts, VND values, and platform used." }, ],
